// client/src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

// Временные простые компоненты для страниц
const HomePage = () => <div style={{padding: '20px'}}><h1>Главная страница</h1></div>;
const CatsPage = () => <div style={{padding: '20px'}}><h1>Страница кошек</h1></div>;
const ExplorePage = () => <div style={{padding: '20px'}}><h1>Страница исследований</h1></div>;
const VillagePage = () => <div style={{padding: '20px'}}><h1>Страница поселения</h1></div>;
const TasksPage = () => <div style={{padding: '20px'}}><h1>Страница заданий</h1></div>;

function App() {
  return (
    <Router>
      <div className="app">
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/cats" element={<CatsPage />} />
          <Route path="/explore" element={<ExplorePage />} />
          <Route path="/village" element={<VillagePage />} />
          <Route path="/tasks" element={<TasksPage />} />
        </Routes>

        {/* Простая навигация внизу страницы */}
        <div style={{
          position: 'fixed',
          bottom: 0,
          left: 0,
          right: 0,
          display: 'flex',
          justifyContent: 'space-around',
          background: 'white',
          padding: '10px',
          boxShadow: '0 -2px 5px rgba(0,0,0,0.1)'
        }}>
          <a href="/">Главная</a>
          <a href="/cats">Кошки</a>
          <a href="/explore">Исследовать</a>
          <a href="/village">Поселение</a>
          <a href="/tasks">Задачи</a>
        </div>
      </div>
    </Router>
  );
}

export default App;
